SELECT festival_id, description, start_date, end_date, status
FROM FESTIVAL
WHERE festival_id = #{festival_id}

SELECT accommodation_id, description, phone, price, status, areaCode, category
FROM ACCOMMODATION
WHERE accommodation_id = #{accommodation_id}

SELECT restaurant_id, description, phone, category, status, restDate, areaCode
FROM RESTAURANT
WHERE restaurant_id = #{restaurant_id}

SELECT price
FROM FESTIVAL_TICKET
WHERE ticket_id = #{ticket_id}

SELECT r.reservation_id, r.user_id, r.place_id, r.check_in, r.check_out, r.visit_time, r.ticket_id, r.guest_count, r.request_note, r.status, r.payment_id, r.created_at AS res_created_at, r.updated_at AS res_updated_at,
p.place_type, p.name, p.address, p.view_count, p.latitude, p.longitude, p.image_url, p.created_at AS place_created_at, p.updated_at AS place_updated_at,
py.amount FROM RESERVATION r JOIN PLACE p ON r.place_id = p.place_id LEFT JOIN PAYMENT py ON r.reservation_id = py.reservation_id WHERE r.reservation_id = #{reservation_id}

