UPDATE PAYMENT
SET payment_status = 'COMPLETED'
WHERE reservation_id = #{reservationId}

UPDATE RESERVATION
SET status = 'RESERVED'
WHERE reservation_id = #{reservationId}

UPDATE PAYMENT
SET amount = #{amount}
WHERE reservation_id = #{reservation_id}

UPDATE RESERVATION
SET payment_id = #{payment_id}
WHERE reservation_id = #{reservation_id}
